package com.arena.studynotes;import android.text.*;import java.util.regex.*;
public class Markdown{static String esc(String s){return TextUtils.htmlEncode(s==null?"":s);}static String html(Note n){String b=esc(n.body);b=b.replaceAll("(?m)^### (.*)$","<h3>$1</h3>").replaceAll("(?m)^## (.*)$","<h2>$1</h2>").replaceAll("(?m)^# (.*)$","<h1>$1</h1>");b=b.replaceAll("\\*\\*(.+?)\\*\\*","<strong>$1</strong>").replaceAll("`([^`]+)`","<code>$1</code>");b=b.replaceAll("(?m)^- (.*)$","<div class='li'>• $1</div>");b=link(b,"note","🔖");b=link(b,"tip","💡");b=b.replaceAll("\\[web:([^|\\]]+)\\|([^\\]]+)\\]","<a class='chip web' href='$1'>🌐 $2</a>");b=b.replaceAll("\\[img:([^\\]]+)\\]","<figure><img src='$1'/></figure>");b=b.replace("\n","<br>");return "<!doctype html><html dir='rtl'><head><meta name='viewport' content='width=device-width,initial-scale=1,maximum-scale=1'><style>"+css()+"</style></head><body><main>"+b+"</main></body></html>";}static String link(String b,String kind,String icon){Matcher m=Pattern.compile("\\["+kind+":(\\d+)\\|([^\\]]+)\\]").matcher(b);StringBuffer sb=new StringBuffer();while(m.find())m.appendReplacement(sb,"<a class='chip' href='"+kind+"://"+m.group(1)+"'>"+icon+" "+m.group(2)+"</a>");m.appendTail(sb);return sb.toString();}static String hx(int c){return String.format("#%06X",0xffffff&c);}static String css(){return "html,body{margin:0;background:"+hx(Theme.bg)+";color:"+hx(Theme.text)+";font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;}main{padding:22px 24px 56px;line-height:1.95;font-size:20px;text-align:right}h1,h2,h3{color:"+hx(Theme.primary)+";line-height:1.45;margin:28px 0 12px;font-weight:900}h1{font-size:30px}h2{font-size:25px}h3{font-size:22px}h1:after,h2:after{content:'';display:block;width:86px;height:4px;border-radius:8px;background:"+hx(Theme.primary)+";margin-top:8px}strong{font-weight:900}code{direction:ltr;unicode-bidi:embed;background:"+hx(Theme.surface2)+";border:1px solid "+hx(Theme.stroke)+";border-radius:10px;padding:3px 8px;font-size:18px}.li{margin:8px 0;padding-right:4px}.chip{display:inline-block;vertical-align:baseline;margin:0 3px;padding:1px 9px;border-radius:10px;background:"+hx(Theme.surface2)+";color:"+hx(Theme.primary)+";font-weight:800;text-decoration:none;border:1px solid "+hx(Theme.stroke)+"}.web{color:#1976d2}figure{margin:18px 0}img{display:block;max-width:100%;border-radius:20px;border:1px solid "+hx(Theme.stroke)+";box-shadow:0 8px 26px rgba(0,0,0,.10)}";}}
